/* ============================================================
   CSS Reset
   ============================================================ */
html {
  box-sizing: border-box;
  font-size: 16px;
}

*,
*:before,
*:after {
  box-sizing: inherit;
}

html,
body {
  height: 100%;
  margin: 0;
}

body,
p,
ol,
ul {
  margin: 0;
  padding: 0;
  font-weight: normal;
}

ol,
ul {
  list-style: none;
}

img {
  max-width: 100%;
  height: auto;
}

a {
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

a[data-msg]:hover {
  cursor: pointer;
}

/* ============================================================
   App shell — 3-pane grid (sidebar | main)
   Structural only; colours/typography come from the theme.
   ============================================================ */
#app {
  display: grid;
  grid-template-columns: var(--sidebar-w, 280px) 1fr;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

/* ---- Left sidebar ---- */
#sidebar {
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow: hidden;
  background-color: var(--colbg3);
}

#sidebar > #header {
  flex: 0 0 auto;
}

#explorer-search {
  flex: 0 0 auto;
  position: relative;
}

#explorer-search #search {
  width: 100%;
}

#search-results {
  position: absolute;
  left: 0;
  right: 0;
  top: 100%;
  z-index: 5;
  max-height: 60vh;
  overflow-y: auto;
  background: var(--colbg2);
}

#explorer {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
}

#sidebar-footer {
  flex: 0 0 auto;
}

/* ---- Main pane ---- */
#main {
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

#main-topbar {
  flex: 0 0 auto;
  display: flex;
  align-items: stretch;
}

#tab-strip {
  flex: 1 1 auto;
  display: flex;
  align-items: stretch;
  overflow-x: auto;
  overflow-y: hidden;
}

#visible-tiddlers {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
}

#menu-toggle {
  display: none;
  flex: 0 0 auto;
}

/* Tabbed story: show only the active note. Gated behind `.tabbed`
   (added by the tabs plugin) so this is a no-op when the plugin is
   absent — notes then simply stack as before. */
#visible-tiddlers.tabbed > .tiddler {
  display: none;
}

#visible-tiddlers.tabbed > .tiddler.tab-active {
  display: block;
}

/* ============================================================
   Responsive — sidebar collapses to a slide-in drawer
   ============================================================ */
@media (max-width: 600px) {
  html {
    font-size: 14px;
  }

  #app {
    grid-template-columns: 1fr;
  }

  #sidebar {
    position: fixed;
    z-index: 20;
    top: 0;
    bottom: 0;
    left: 0;
    width: min(85vw, var(--sidebar-w, 280px));
    transform: translateX(-100%);
    transition: transform 0.2s ease;
    box-shadow: 2px 0 12px var(--col0);
  }

  #sidebar.open {
    transform: translateX(0);
  }

  #menu-toggle {
    display: inline-flex;
    align-items: center;
  }
}

/* ============================================================
   Fallback design tokens (in case a theme forgets them)
   ============================================================ */
:root {
  --colbg1: #fdeeee;
  --colbg2: #efefef;
  --colbg3: #dfdfdf;
  --colbgi: #efefef;
  --colfgi: #373737;
  --colfg: #323232;
  --col0: #323232;
  --col1: #6e6e6e;
  --col3: #8fbfdf;
  --col4: #8d8d8d;
  --col6: #6db193;
  --notify-rgba: 210, 180, 90;
  --rad1: 0.3rem;
  --rad2: 0.3rem;
  --rad3: 0.3rem;
  --rad4: 0.3rem;
  /* New layout tokens */
  --sidebar-w: 280px;
  --accent: #6db193;
  --accent-2: #8fbfdf;
  --tab-bg: #dfdfdf;
  --tab-active-bg: #efefef;
}

/* ============================================================
   Settings form ($SettingsDialogPlugin) — in-place editable form
   rendered over the $GeneralSettings JSON. Namespaced so it does
   not collide with the global tab strip (.tab / .tab-active).
   ============================================================ */
.settings-form {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}
.settings-tabs {
  display: flex;
  flex-wrap: wrap;
  gap: 0.25rem;
  border-bottom: 1px solid var(--col4);
}
.settings-tab {
  padding: 0.4rem 0.8rem;
  cursor: pointer;
  border: none;
  background: none;
  color: inherit;
  font: inherit;
  border-bottom: 2px solid transparent;
  margin-bottom: -1px;
}
.settings-tab:hover {
  background: var(--tab-bg);
}
.settings-tab-active {
  font-weight: 600;
  border-bottom-color: var(--accent);
}
.settings-tab-panel.is-hidden {
  display: none;
}
.settings-section {
  margin: 0.5rem 0 1rem;
}
.settings-section-title {
  font-weight: 600;
  margin-bottom: 0.5rem;
  padding-bottom: 0.25rem;
  border-bottom: 1px solid var(--colbg3);
}
.settings-field {
  display: grid;
  grid-template-columns: minmax(8rem, 30%) 1fr;
  gap: 0.5rem 1rem;
  align-items: start;
  margin: 0.4rem 0;
}
.settings-field-label {
  font-weight: 500;
  padding-top: 0.3rem;
}
.settings-field-help {
  font-weight: 400;
  font-size: 0.85em;
  color: var(--col1);
  margin-top: 0.15rem;
}
.settings-field-input {
  width: 100%;
  box-sizing: border-box;
}
input.settings-field-input[type="checkbox"] {
  width: auto;
}
.settings-text {
  min-height: 3rem;
}
.settings-json {
  width: 100%;
  box-sizing: border-box;
  font-family: monospace;
  min-height: 5rem;
}
.settings-options {
  display: flex;
  flex-wrap: wrap;
  gap: 0.25rem 1rem;
  padding-top: 0.3rem;
}
.settings-option {
  font-weight: 400;
}
.settings-error {
  color: #b00;
  background: var(--colbg1);
  border: 1px solid #b00;
  border-radius: var(--rad1);
  padding: 0.4rem 0.6rem;
  margin-bottom: 0.5rem;
}

/* ============================================================
   $ThemeBase — universal component styling for the 3-pane UI.
   Token-driven: themes recolour everything by overriding the
   CSS variables (see $StyleSheetCore for the fallback set).
   Structure/layout lives in $StyleSheetCore; this file is looks.
   ============================================================ */

* {
  font-family:
    -apple-system,
    system-ui,
    'Segoe UI',
    Inter,
    Roboto,
    Helvetica,
    Arial,
    sans-serif;
}

body {
  background-color: var(--colbg1);
  color: var(--colfg);
  font-size: 0.95rem;
  line-height: 1.5;
}

a:not([class]) {
  color: var(--col6);
  font-weight: 600;
  text-decoration-skip-ink: auto;
}

/* Thin, unobtrusive scrollbars everywhere */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--col4) transparent;
}

/* ============================================================
   Sidebar + explorer
   ============================================================ */
#sidebar {
  border-right: 1px solid var(--col4);
}

#sidebar > #header {
  padding: 12px 14px 6px;
}

#site-title h1 {
  font-size: 1.15rem;
  font-weight: 700;
  padding: 0;
  margin: 0;
  letter-spacing: -0.01em;
}

#site-subtitle {
  font-size: 0.75rem;
  color: var(--col1);
}

#explorer-search {
  padding: 6px 12px 10px;
}

#explorer {
  padding: 4px 8px 12px;
}

.explorer-section-title {
  font-size: 0.68rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--col1);
  padding: 12px 8px 4px;
}

a.explorer-note {
  display: block;
  padding: 4px 10px;
  border-radius: var(--rad1);
  color: var(--colfg);
  font-size: 0.9rem;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

a.explorer-note:hover {
  background-color: var(--colbg2);
  text-decoration: none;
}

a.explorer-note.open {
  color: var(--col6);
}

.explorer-empty {
  padding: 6px 10px;
  color: var(--col1);
  font-size: 0.85rem;
  font-style: italic;
}

.explorer-tags-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  padding: 4px 8px;
}

a.explorer-tag {
  padding: 2px 10px;
  border-radius: 999px;
  background-color: var(--colbg2);
  border: 1px solid var(--col4);
  color: var(--col1);
  font-size: 0.78rem;
  cursor: pointer;
}

a.explorer-tag:hover {
  color: var(--col6);
  border-color: var(--col6);
  text-decoration: none;
}

/* Sidebar footer: existing toolbar + selectors */
#sidebar-footer {
  border-top: 1px solid var(--col4);
  padding: 8px 12px;
}

#header-tools {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  align-items: center;
}

.sidebar-selectors {
  display: flex;
  gap: 6px;
  margin-top: 8px;
}

.sidebar-selectors select {
  flex: 1;
  min-width: 0;
}

/* ============================================================
   Main pane — top bar, tabs
   ============================================================ */
#main-topbar {
  background-color: var(--colbg3);
  border-bottom: 1px solid var(--col4);
  min-height: 38px;
}

#menu-toggle {
  padding: 0 12px;
  font-size: 1.1rem;
  color: var(--col1);
  background: transparent;
  border: none;
}

#tab-strip {
  scrollbar-width: none;
}

#tab-strip::-webkit-scrollbar {
  display: none;
}

.tab {
  display: flex;
  align-items: center;
  gap: 8px;
  max-width: 200px;
  padding: 8px 12px;
  background-color: var(--tab-bg);
  border-right: 1px solid var(--col4);
  color: var(--col1);
  font-size: 0.85rem;
  cursor: pointer;
  user-select: none;
}

.tab .tab-label {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tab.active {
  background-color: var(--tab-active-bg);
  color: var(--colfg);
  box-shadow: inset 0 2px 0 var(--accent);
}

.tab .tab-close {
  padding: 0 2px;
  font-size: 0.85rem;
  line-height: 1;
  color: var(--col1);
  background: transparent;
  border: none;
  opacity: 0;
  cursor: pointer;
}

.tab:hover .tab-close,
.tab.active .tab-close {
  opacity: 0.7;
}

.tab .tab-close:hover {
  opacity: 1;
  color: var(--col6);
}

.tab-new {
  padding: 0 12px;
  font-size: 1.1rem;
  color: var(--col1);
  background: transparent;
  border: none;
  cursor: pointer;
}

.tab-new:hover {
  color: var(--col6);
}

/* ============================================================
   Notes (cards / active pane)
   ============================================================ */
#visible-tiddlers {
  padding: 0;
}

div.tiddler {
  max-width: 860px;
  margin: 24px auto;
  padding: 24px 32px;
  background-color: var(--colbg2);
  border: 1px solid var(--col4);
  border-radius: var(--rad1) var(--rad2) var(--rad3) var(--rad4);
}

div.tiddler-nosave {
  border-color: var(--col6);
}

div.tiddler-readonly {
  border-left: 3px solid var(--col1);
}

div.shadowtrue {
  border-left: 3px solid var(--col4);
}

div.shadowtrue div.title {
  font-style: italic;
}

div.tiddler div.title {
  font-size: 1.6rem;
  font-weight: 700;
  line-height: 1.25;
  letter-spacing: -0.01em;
  padding-bottom: 10px;
  margin-bottom: 14px;
  border-bottom: 1px solid var(--col4);
}

div.tiddler div.title button {
  border: none;
  background: transparent;
  float: right;
}

div.tiddler div.modified {
  text-align: right;
  font-style: italic;
  font-size: 0.78rem;
  color: var(--col1);
}

div.tiddler div.text {
  scrollbar-color: var(--col4) transparent;
  scrollbar-width: thin;
}

div.tiddler div.text p {
  margin: 14px 0;
}

div.tiddler div.tags {
  font-size: 0.78rem;
  color: var(--col1);
  margin-top: 16px;
}

div.tiddler div.meta {
  text-align: right;
  font-size: 0.72rem;
  color: var(--col1);
}

/* ============================================================
   Buttons
   ============================================================ */
button {
  fill: var(--col1);
  color: var(--colfg);
  border: 1px solid var(--col4);
  background-color: var(--col3);
  border-radius: var(--rad1);
  padding: 4px 10px;
  cursor: pointer;
}

button:hover {
  filter: brightness(1.1);
}

button.icon {
  fill: var(--col1);
  background-color: transparent;
  border: none;
  padding: 4px;
  cursor: pointer;
}

button.icon:hover svg,
button:hover svg {
  fill: var(--col6);
}

/* ============================================================
   Forms & inputs
   ============================================================ */
input,
textarea,
select {
  background-color: var(--colbgi);
  color: var(--colfgi);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  padding: 6px 8px;
  font-size: 0.9rem;
}

input:focus,
textarea:focus,
select:focus {
  outline: none;
  border-color: var(--col6);
}

#search {
  padding: 8px 10px;
}

#search-results {
  padding: 8px;
  background: var(--colbg2);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.4);
}

#search-results .tiddler-list {
  padding: 4px 8px;
  border-radius: var(--rad1);
}

#search-results .tiddler-list:hover {
  background-color: var(--colbg3);
}

#search-results a {
  color: var(--colfg);
}

/* ============================================================
   Dialogs (edit / preview)
   ============================================================ */
dialog::backdrop {
  background-color: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(2px);
}

dialog#new-dialog {
  width: 70%;
  height: 75%;
  background-color: var(--colbg2);
  color: var(--colfg);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
}

dialog#new-dialog form {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

dialog#new-dialog form div.text {
  flex-grow: 1;
  min-height: 240px;
}

dialog#new-dialog form input,
dialog#new-dialog form textarea {
  width: 100%;
  height: 100%;
}

dialog#new-dialog div.title input {
  font-size: 1.2rem;
  font-weight: 700;
}

dialog#new-dialog div.toolbar {
  text-align: right;
}

dialog#preview-dialog {
  width: 90%;
  height: 90%;
  min-height: 500px;
  border: 0;
  background-color: transparent;
  overflow-y: hidden;
}

dialog#preview-dialog div.tiddler {
  height: 100%;
  max-width: none;
  margin: 0;
}

dialog#preview-dialog div.text {
  height: 100%;
  max-height: 1000px;
}

/* ============================================================
   Command palette
   ============================================================ */
dialog#command-palette {
  position: fixed;
  top: 12vh;
  left: 50%;
  transform: translateX(-50%);
  width: min(640px, 92vw);
  max-height: 70vh;
  padding: 0;
  background-color: var(--colbg2);
  color: var(--colfg);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  box-shadow: 0 12px 48px rgba(0, 0, 0, 0.55);
  overflow: hidden;
}

#palette-input {
  width: 100%;
  border: none;
  border-bottom: 1px solid var(--col4);
  border-radius: 0;
  background: transparent;
  padding: 14px 16px;
  font-size: 1.05rem;
}

#palette-results {
  max-height: 56vh;
  overflow-y: auto;
  padding: 6px;
}

.palette-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 12px;
  border-radius: var(--rad1);
  cursor: pointer;
}

.palette-row.selected,
.palette-row:hover {
  background-color: var(--col3);
  color: #fff;
}

.palette-label {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.palette-hint {
  font-size: 0.72rem;
  color: var(--col1);
  flex: 0 0 auto;
}

.palette-row.selected .palette-hint,
.palette-row:hover .palette-hint {
  color: rgba(255, 255, 255, 0.75);
}

.palette-empty {
  padding: 14px 16px;
  color: var(--col1);
  font-style: italic;
}

/* ============================================================
   Notifications
   ============================================================ */
#notify {
  position: fixed;
  z-index: 30;
  left: 50%;
  transform: translate(-50%);
  bottom: 16px;
  min-width: 250px;
  max-width: 80vw;
  background-color: rgba(var(--notify-rgba), 0.96);
  color: #fff;
  text-align: left;
  border-radius: var(--rad1);
  box-shadow: 0 8px 28px rgba(0, 0, 0, 0.5);
  padding: 14px 18px;
  line-height: 1.35;
}

div.notifyHidden {
  visibility: hidden;
  opacity: 0;
  transition: visibility 0.3s linear, opacity 0.3s linear;
}

div.notifyShow {
  visibility: visible;
  opacity: 1;
  transition: visibility 0.3s linear, opacity 0.3s linear;
}

/* ============================================================
   Typography & content
   ============================================================ */
h1 { font-size: 1.8rem; padding: 4px 0; }
h2 { font-size: 1.45rem; padding: 4px 0; }
h3 { font-size: 1.2rem; padding: 3px 0; }
h4 { font-size: 1.05rem; padding: 2px 0; }

div.tiddler ul,
div.tiddler ol {
  margin-left: 1.4em;
  margin-bottom: 0.6em;
}

div.tiddler ul { list-style: disc; }
div.tiddler ol { list-style: decimal; }

li li {
  margin-left: 16px;
}

blockquote {
  background-color: var(--colbg3);
  border-left: 4px solid var(--col6);
  margin: 1.2em 0;
  padding: 0.6em 1em;
  border-radius: 0 var(--rad1) var(--rad1) 0;
  quotes: "\201C" "\201D" "\2018" "\2019";
}

code {
  background-color: var(--colbg3);
  font-family: 'Cascadia Code', Consolas, 'Courier New', monospace;
  padding: 0.15rem 0.4rem;
  margin: 0 0.15rem;
  font-size: 88%;
  border: 1px solid var(--col4);
  border-radius: 4px;
}

pre {
  white-space: pre-wrap;
}

pre > code {
  display: block;
  padding: 1rem 1.25rem;
  white-space: pre;
  overflow-x: auto;
}

table {
  border-collapse: collapse;
}

th,
td {
  padding: 6px 10px;
  border: 1px solid var(--col4);
}

th {
  font-weight: 700;
  background-color: var(--col3);
  color: #fff;
}

span.error {
  color: #fff;
  background-color: #c0392b;
  padding: 0 4px;
  border-radius: 3px;
}
